            Object orderBook = this.parseOrderBook(data, Helpers.GetValue(market, "symbol"), timestamp, "bids", "asks", "price", "amount");
            Helpers.addElementToObject(orderBook, "nonce", this.safeInteger(data, "lastUpdateId"));
