    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades
        //     {
        //         "id": "7407825178362667008",
        //         "symbol": "ETH-USDT",
        //         "price": "2970.49",
        //         "quantity": "63",
        //         "side": "SELL",
        //         "time": 1766163153218
        //     }
        //
        // fetchMyTrades
        //     {
        //         "orderId": "7408919189505597440",
        //         "wallet": "W001",
        //         "symbol": "ETH-USDC",
        //         "time": "1766423985842",
        //         "dealPrice": "3032.45",
        //         "dealVolume": "1",
        //         "fee": "0",
        //         "side": "BUY",
        //         "type": "2",
        //         "liqPrice": null,
        //         "basePrecision": "8",
        //         "baseShowPrecision": "2",
        //         "tradePnl": "0",
        //         "marginType": "CROSS",
        //         "leverageLevel": 1
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(trade, "symbol");
        market = this.safeMarket(marketId, market);
        Object timestamp = this.safeInteger(trade, "time");
        Object fee = null;
        Object rawType = this.safeString(trade, "type");
        Object feeCost = this.safeString(trade, "fee");
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            final Object finalFeeCost = feeCost;
            final Object finalMarket = market;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCost );
                put( "currency", Helpers.GetValue(finalMarket, "settle") );
            }};
        }
        Object orderId = this.safeString(trade, "orderId");
        Object side = null; // fetchMyTrades always returns side BUY
        if (Helpers.isTrue(Helpers.isEqual(orderId, null)))
        {
            // from fetchTrades
            side = this.safeStringLower(trade, "side");
        }
        final Object finalMarket_2 = market;
        final Object finalOrderId = orderId;
        final Object finalSide = side;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "timestamp", timestamp );
            put( "datetime", BydfiCore.this.iso8601(timestamp) );
            put( "symbol", Helpers.GetValue(finalMarket_2, "symbol") );
            put( "id", BydfiCore.this.safeString(trade, "id") );
            put( "order", finalOrderId );
            put( "type", BydfiCore.this.parseTradeType(rawType) );
            put( "side", finalSide );
            put( "takerOrMaker", null );
            put( "price", BydfiCore.this.safeString2(trade, "price", "dealPrice") );
            put( "amount", BydfiCore.this.safeString2(trade, "quantity", "dealVolume") );
            put( "cost", null );
            put( "fee", finalFee );
        }}, market);
    }

