    public Object handleSinceAndUntil(Object methodName, Object... optionalArgs)
    {
        Object since = Helpers.getArg(optionalArgs, 0, null);
        Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
        Object until = null;
        var untilparametersVariable = this.handleOptionAndParams2(parameters, methodName, "until", "endTime");
        until = ((java.util.List<Object>) untilparametersVariable).get(0);
        parameters = ((java.util.List<Object>) untilparametersVariable).get(1);
        Object now = this.milliseconds();
        Object sevenDays = Helpers.multiply(Helpers.multiply(Helpers.multiply(Helpers.multiply(7, 24), 60), 60), 1000); // the maximum range is 7 days
        Object startTime = since;
        if (Helpers.isTrue(Helpers.isEqual(startTime, null)))
        {
            if (Helpers.isTrue(Helpers.isEqual(until, null)))
            {
                // both since and until are undefined
                startTime = Helpers.subtract(now, sevenDays);
                until = now;
            } else
            {
                // since is undefined but until is defined
                startTime = Helpers.subtract(until, sevenDays);
            }
        } else if (Helpers.isTrue(Helpers.isEqual(until, null)))
        {
            // until is undefined but since is defined
            Object delta = Helpers.subtract(now, startTime);
            if (Helpers.isTrue(Helpers.isGreaterThan(delta, sevenDays)))
            {
                until = Helpers.add(startTime, sevenDays);
            } else
            {
                until = now;
            }
        }
        final Object finalStartTime = startTime;
        final Object finalUntil = until;
        Object request = new java.util.HashMap<String, Object>() {{
            put( "startTime", finalStartTime );
            put( "endTime", finalUntil );
        }};
        return this.extend(request, parameters);
    }

    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        // createOrder, fetchOpenOrders, fetchOpenOrder
        //     {
        //         "wallet": "W001",
        //         "symbol": "ETH-USDT",
        //         "orderId": "7408875768086683648",
        //         "clientOrderId": "7408875768086683648",
        //         "price": "1000",
        //         "origQty": "10",
        //         "avgPrice": "0",
        //         "executedQty": "0",
        //         "orderType": "LIMIT",
        //         "side": "BUY",
        //         "status": "CANCELED",
        //         "stopPrice": null,
        //         "activatePrice": null,
        //         "timeInForce": null,
        //         "workingType": "CONTRACT_PRICE",
        //         "positionSide": "BOTH",
        //         "priceProtect": false,
        //         "reduceOnly": false,
        //         "closePosition": false,
        //         "createTime": "1766413633367",
        //         "updateTime": "1766413633370"
        //     }
        //
        // fetchCanceledAndClosedOrders
        //     {
        //         "orderId": "7408919189505597440",
        //         "orderType": "MARKET",
        //         "symbol": "ETH-USDC",
        //         "origQty": "1",
        //         "side": "BUY",
        //         "positionSide": "BOTH",
        //         "positionAvgPrice": null,
        //         "positionVolume": null,
        //         "positionType": null,
        //         "reduceOnly": false,
        //         "closePosition": false,
        //         "action": null,
        //         "price": "3032.45",
        //         "avgPrice": "3032.45",
        //         "brkPrice": null,
        //         "dealVolume": null,
        //         "status": "2",
        //         "wallet": "W001",
        //         "alias": null,
        //         "contractId": null,
        //         "mtime": "1766423985842",
        //         "ctime": "1766423985840",
        //         "fixedPrice": null,
        //         "direction": null,
        //         "triggerPrice": null,
        //         "priceType": null,
        //         "basePrecision": "8",
        //         "baseShowPrecision": "2",
        //         "strategyType": null,
        //         "leverageLevel": 1,
        //         "marginType": "CROSS",
        //         "remark": null,
        //         "callbackRate": null,
        //         "activationPrice": null
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(order, "symbol");
        market = this.safeMarket(marketId, market);
        Object timestamp = this.safeInteger2(order, "createTime", "ctime");
        Object rawType = this.safeString(order, "orderType");
        Object stopPrice = this.safeStringN(order, new java.util.ArrayList<Object>(java.util.Arrays.asList("stopPrice", "activatePrice", "triggerPrice")));
        Object isStopLossOrder = Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(rawType, "STOP"))) || Helpers.isTrue((Helpers.isEqual(rawType, "STOP_MARKET")))) || Helpers.isTrue((Helpers.isEqual(rawType, "TRAILING_STOP_MARKET")));
        Object isTakeProfitOrder = Helpers.isTrue((Helpers.isEqual(rawType, "TAKE_PROFIT"))) || Helpers.isTrue((Helpers.isEqual(rawType, "TAKE_PROFIT_MARKET")));
        Object rawTimeInForce = this.safeString(order, "timeInForce");
        Object timeInForce = this.parseOrderTimeInForce(rawTimeInForce);
        Object postOnly = null;
        if (Helpers.isTrue(Helpers.isEqual(timeInForce, "PO")))
        {
            postOnly = true;
        }
        Object rawStatus = this.safeString(order, "status");
        Object fee = new java.util.HashMap<String, Object>() {{}};
        Object quoteFee = this.safeNumber(order, "quoteFee");
        if (Helpers.isTrue(!Helpers.isEqual(quoteFee, null)))
        {
            Helpers.addElementToObject(fee, "cost", quoteFee);
            Helpers.addElementToObject(fee, "currency", Helpers.GetValue(market, "quote"));
        }
        final Object finalMarket = market;
        final Object finalRawType = rawType;
        final Object finalTimeInForce = timeInForce;
        final Object finalPostOnly = postOnly;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "info", order );
            put( "id", BydfiCore.this.safeString(order, "orderId") );
            put( "clientOrderId", BydfiCore.this.safeString(order, "clientOrderId") );
            put( "timestamp", timestamp );
            put( "datetime", BydfiCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "lastUpdateTimestamp", BydfiCore.this.safeInteger2(order, "updateTime", "mtime") );
            put( "status", BydfiCore.this.parseOrderStatus(rawStatus) );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "type", BydfiCore.this.parseOrderType(finalRawType) );
            put( "timeInForce", finalTimeInForce );
            put( "postOnly", finalPostOnly );
            put( "reduceOnly", BydfiCore.this.safeBool(order, "reduceOnly") );
            put( "side", BydfiCore.this.safeStringLower(order, "side") );
            put( "price", BydfiCore.this.safeString(order, "price") );
            put( "triggerPrice", stopPrice );
            put( "stopLossPrice", ((Helpers.isTrue(isStopLossOrder))) ? stopPrice : null );
            put( "takeProfitPrice", ((Helpers.isTrue(isTakeProfitOrder))) ? stopPrice : null );
            put( "amount", BydfiCore.this.safeString(order, "origQty") );
            put( "filled", BydfiCore.this.safeString(order, "executedQty") );
            put( "remaining", null );
            put( "cost", null );
            put( "trades", null );
            put( "fee", fee );
            put( "average", BydfiCore.this.omitZero(BydfiCore.this.safeString(order, "avgPrice")) );
        }}, market);
    }

