    public Object parsePosition(Object position, Object... optionalArgs)
    {
        //
        // fetchPositions, fetchPositionsForSymbol
        //     {
        //         "symbol": "ETH-USDC",
        //         "side": "BUY",
        //         "volume": "0.001",
        //         "avgPrice": "3032.45",
        //         "liqPrice": "0",
        //         "markPrice": "3032.37",
        //         "unPnl": "-0.00008",
        //         "positionMargin": "0",
        //         "settleCoin": "USDC",
        //         "im": "3.03245",
        //         "mm": "0.007581125"
        //     }
        //
        // fetchPositionsHistory
        //     {
        //         "id": "16788366",
        //         "wallet": "W001",
        //         "currency": "USDC",
        //         "symbol": "ETH-USDC",
        //         "side": "BUY",
        //         "positionSide": "BOTH",
        //         "leverage": 1,
        //         "avgOpenPositionPrice": "3032.45",
        //         "openPositionVolume": "1",
        //         "openCount": 1,
        //         "highPrice": "3032.45",
        //         "lowPrice": "2953.67",
        //         "avgClosePositionPrice": "2953.67",
        //         "closePositionVolume": "1",
        //         "closePositionCost": "2.95367",
        //         "closeCount": 1,
        //         "positionProfits": "-0.07878",
        //         "lossBonus": "0",
        //         "capitalFeeTotal": "-0.00026361",
        //         "capitalFeeOutCash": "-0.00026361",
        //         "capitalFeeInCash": "0",
        //         "capitalFeeBonus": "0",
        //         "openFeeTotal": "-0.00181947",
        //         "openFeeBonus": "0",
        //         "closeFeeTotal": "-0.00177221",
        //         "closeFeeBonus": "0",
        //         "liqLoss": "0",
        //         "liqClosed": false,
        //         "sequence": "53685341336",
        //         "updateTime": "1766494929423",
        //         "createTime": "1766423985842"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(position, "symbol");
        market = this.safeMarket(marketId, market);
        Object buyOrSell = this.safeString(position, "side");
        Object rawPositionSide = this.safeStringLower(position, "positionSide");
        Object positionSide = this.parsePositionSide(buyOrSell);
        Object hedged = null;
        Object isFetchPositionsHistory = false;
        if (Helpers.isTrue(!Helpers.isEqual(rawPositionSide, null)))
        {
            isFetchPositionsHistory = true;
            if (Helpers.isTrue(!Helpers.isEqual(rawPositionSide, "both")))
            {
                positionSide = rawPositionSide;
                hedged = true;
            } else
            {
                hedged = false;
            }
        }
        Object contractSize = this.safeString(market, "contractSize");
        Object contracts = this.safeString2(position, "volume", "openPositionVolume");
        if (!Helpers.isTrue(isFetchPositionsHistory))
        {
            // in fetchPositions, the 'volume' is in base currency units, need to convert to contracts
            contracts = Precise.stringDiv(contracts, contractSize);
        }
        Object timestamp = this.safeInteger(position, "createTime");
        final Object finalMarket = market;
        final Object finalPositionSide = positionSide;
        final Object finalContracts = contracts;
        final Object finalHedged = hedged;
        return this.safePosition(new java.util.HashMap<String, Object>() {{
            put( "info", position );
            put( "id", BydfiCore.this.safeString(position, "id") );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "entryPrice", BydfiCore.this.parseNumber(BydfiCore.this.safeString2(position, "avgOpenPositionPrice", "avgPrice")) );
            put( "markPrice", BydfiCore.this.parseNumber(BydfiCore.this.safeString(position, "markPrice")) );
            put( "lastPrice", BydfiCore.this.parseNumber(BydfiCore.this.safeString(position, "avgClosePositionPrice")) );
            put( "notional", BydfiCore.this.parseNumber(BydfiCore.this.safeString(position, "closePositionCost")) );
            put( "collateral", null );
            put( "unrealizedPnl", BydfiCore.this.parseNumber(BydfiCore.this.safeString(position, "unPnl")) );
            put( "realizedPnl", BydfiCore.this.parseNumber(BydfiCore.this.safeString(position, "positionProfits")) );
            put( "side", finalPositionSide );
            put( "contracts", BydfiCore.this.parseNumber(finalContracts) );
            put( "contractSize", BydfiCore.this.parseNumber(contractSize) );
            put( "timestamp", timestamp );
            put( "datetime", BydfiCore.this.iso8601(timestamp) );
            put( "lastUpdateTimestamp", BydfiCore.this.safeInteger(position, "updateTime") );
            put( "hedged", finalHedged );
            put( "maintenanceMargin", BydfiCore.this.parseNumber(BydfiCore.this.safeString(position, "mm")) );
            put( "maintenanceMarginPercentage", null );
            put( "initialMargin", BydfiCore.this.parseNumber(BydfiCore.this.safeString(position, "im")) );
            put( "initialMarginPercentage", null );
            put( "leverage", BydfiCore.this.parseNumber(BydfiCore.this.safeString(position, "leverage")) );
            put( "liquidationPrice", BydfiCore.this.parseNumber(BydfiCore.this.safeString(position, "liqPrice")) );
            put( "marginRatio", null );
            put( "marginMode", null );
            put( "percentage", null );
        }});
    }

